const spinner = document.getElementById('spinner');
const totalCards = himaphanData.length;

// ปรับความกว้างการ์ดและคำนวณรัศมีวงกลม
const cardWidth = 300; 
const radius = Math.round((cardWidth / 2) / Math.tan(Math.PI / totalCards));
document.documentElement.style.setProperty('--radius', `${radius}px`);

// สร้างการ์ดในวงกลม
himaphanData.forEach((animal, index) => {
    const card = document.createElement('div');
    card.className = 'card';
    const angle = (index / totalCards) * 360;
    card.style.transform = `rotateY(${angle}deg) translateZ(${radius}px)`;
    card.innerHTML = `<img src="${animal.img}" alt="${animal.name}" onerror="this.src='https://via.placeholder.com/250x350/222/d4af37?text=${encodeURIComponent(animal.name)}'">`;
    card.onclick = () => openModal(animal);
    spinner.appendChild(card);
});

// --- ระบบ Catalog เมนูทางลัด ---
function toggleCatalog() {
    const catalog = document.getElementById('catalogModal');
    if (catalog.style.display === 'block') {
        catalog.style.display = 'none';
        spinner.style.animationPlayState = 'running';
    } else {
        renderCatalog();
        catalog.style.display = 'block';
        spinner.style.animationPlayState = 'paused';
    }
}

function renderCatalog() {
    const catalogList = document.getElementById('catalogList');
    catalogList.innerHTML = '';
    const categories = [...new Set(himaphanData.map(item => item.category))];
    
    categories.forEach(cat => {
        const section = document.createElement('div');
        section.innerHTML = `<h3 class="catalog-category">${cat}</h3>`;
        const grid = document.createElement('div');
        grid.className = 'catalog-grid';
        
        himaphanData.filter(item => item.category === cat).forEach(animal => {
            const div = document.createElement('div');
            div.className = 'catalog-item';
            div.onclick = () => { toggleCatalog(); openModal(animal); };
            div.innerHTML = `
                <img src="${animal.img}" onerror="this.src='https://via.placeholder.com/100x100?text=IMG'">
                <span>${animal.name}</span>
            `;
            grid.appendChild(div);
        });
        section.appendChild(grid);
        catalogList.appendChild(section);
    });
}

// --- ระบบควบคุมการหมุน (Drag & Touch) ---
let isDragging = false;
let startX, startRotation = 0, currentYRotation = 0;

const startAction = (e) => {
    isDragging = true;
    startX = e.pageX || e.touches[0].pageX;
    spinner.style.animation = 'none'; // หยุด Auto Rotate
};

const moveAction = (e) => {
    if (!isDragging) return;
    const x = e.pageX || e.touches[0].pageX;
    const walk = (x - startX) * 0.15; // ความไวในการหมุน
    currentYRotation = startRotation + walk;
    spinner.style.transform = `translateZ(calc(-1 * var(--radius))) rotateY(${currentYRotation}deg)`;
};

const endAction = () => {
    isDragging = false;
    startRotation = currentYRotation;
};

// ผูก Event เข้ากับ Viewport
const viewport = document.querySelector('.gallery-viewport');
viewport.addEventListener('mousedown', startAction);
viewport.addEventListener('touchstart', startAction);
window.addEventListener('mousemove', moveAction);
window.addEventListener('touchmove', moveAction);
window.addEventListener('mouseup', endAction);
window.addEventListener('touchend', endAction);

// --- ระบบ Modal ---
function openModal(animal) {
    const modal = document.getElementById("infoModal");
    document.getElementById("modalTitle").innerText = animal.name;
    document.getElementById("modalCategory").innerText = `หมวดหมู่: ${animal.category}`;
    
    const physicalHTML = `
        <ul style="margin: 5px 0 0 20px; padding: 0;">
            <li><span style="color: #d4af37;">ส่วนหัว:</span> ${animal.physical.head}</li>
            <li><span style="color: #d4af37;">ส่วนลำตัว:</span> ${animal.physical.body}</li>
            <li><span style="color: #d4af37;">อวัยวะพิเศษ:</span> ${animal.physical.special}</li>
        </ul>`;
    document.getElementById("modalPhysical").innerHTML = physicalHTML;
    document.getElementById("modalBehavior").innerText = animal.behavior;
    document.getElementById("modalHabitat").innerText = animal.habitat;
    document.getElementById("modalAbilities").innerText = animal.abilities;
    document.getElementById("modalLore").innerText = animal.lore;
    
    const imgElement = document.getElementById("modalImg");
    imgElement.src = animal.img;
    imgElement.onerror = function() { this.src = `https://via.placeholder.com/300x400/333/d4af37?text=${encodeURIComponent(animal.name)}`; };
    
    modal.style.display = "block";
    spinner.style.animationPlayState = "paused";
}

function closeModal() {
    document.getElementById("infoModal").style.display = "none";
    if (!isDragging) spinner.style.animationPlayState = "running";
}

window.onclick = (event) => { if (event.target == document.getElementById("infoModal")) closeModal(); }

// นี่คือรายชื่อสัตว์หิมพานต์ทั้งหมดจากข้อมูลที่คุณรวบรวมไว้ (รวมถึงตัวที่ผมเพิ่มเติมให้ในหมวดหมู่ที่ว่างอยู่) นำมารวมกันและจัดเรียงลำดับหมายเลขตั้งแต่ 1 ไปจนครบทุกตัว พร้อมคำอธิบายรูปลักษณ์สั้นๆ เพื่อให้เป็นทำเนียบสัตว์หิมพานต์ที่สมบูรณ์และง่ายต่อการสืบค้นครับ

// ### + สัตว์ประเภทกิเลน
// 1. **กิเลนจีน:** หัวคล้ายมังกร มีเขาเดียว ลำตัวมีเกล็ด กีบเท้าแยกแบบวัว สัตว์มงคลแห่งความเมตตา
// 2. **กิเลนไทย:** ลำตัวเพรียวแบบม้า มีเขาและหนวด มีเกล็ด หางเป็นพู่ ไม่เหยียบย่ำสิ่งมีชีวิตเล็กๆ
// 3. **กิเลนปีก:** รูปร่างเหมือนกิเลนไทย แต่มีปีกนกที่ไหล่ ทำให้โบยบินได้

// ### + สัตว์ประเภทกวาง
// 4. **มารีศ:** ยักษ์จำแลงกายเป็นกวางทองขนแวววาว เพื่อหลอกล่อนางสีดาในเรื่องรามเกียรติ์
// 5. **พานรมฤค:** ท่อนบนและหัวเป็นลิง ท่อนล่างและขาเป็นกวาง ปราดเปรียวและว่องไว
// 6. **อัปสรสีหะ:** ท่อนบนเป็นนางฟ้าผู้งดงาม ท่อนล่างยืนสี่ขาคล้ายกวางหรือสิงห์

// ### + สัตว์ประเภทสิงห์
// 7. **บัณฑุราชสีห์:** สิงห์กินเนื้อ กายสีเหลืองอ่อนเหมือนใบไม้ร่วง ดุร้ายและทรงพลัง
// 8. **กาฬสีหะ:** สิงห์กินพืช กายสีดำสนิท กินหญ้าเป็นอาหาร ไม่มีอันตราย
// 9. **ไกรสรราชสีห์:** จ้าวแห่งสัตว์หิมพานต์ กายสีขาว ปาก หาง และเท้าสีแดง เสียงคำรามทรงพลัง
// 10. **ติณสีหะ:** สิงห์กินพืช กายสีแดง รูปร่างคล้ายกาฬสีหะ
// 11. **เกสรสิงห์:** สิงห์ที่มีขนแผงคอ (เกสร) งดงามเป็นเอกลักษณ์
// 12. **เหมราช:** ลำตัวเป็นสิงห์ หัวเป็น "เหม" (สัตว์คล้ายนกผสมจระเข้)
// 13. **คชสีห์:** ลำตัวเป็นสิงห์ หัวและงวงเป็นช้าง สัญลักษณ์ของความกล้าหาญ
// 14. **ไกรสรจำแลง:** สิงห์ที่สามารถแปลงกายเป็นสัตว์อื่นหรือมนุษย์ได้
// 15. **ไกรสรคาวี:** ลำตัวเป็นสิงห์ หัวเป็นวัว (คาวี)
// 16. **ไกรสรนาคา:** ลำตัวเป็นสิงห์ หัวและหางเป็นพญานาค มีเกล็ด
// 17. **ไกรสรปักษา:** ลำตัวเป็นสิงห์ มีปีกและหางเป็นนก โบยบินได้
// 18. **โลโต:** สิงห์ที่มีสีน้ำตาล รูปร่างใกล้เคียงกับสิงโตในธรรมชาติมากที่สุด
// 19. **พยัคฆ์ไกรสร:** ลำตัวเป็นสิงห์ หัวเป็นเสือ (พยัคฆ์) ดุร้ายมาก
// 20. **สางแปรง:** สิงห์ที่มีขนแผงคอและขนตามตัวยาวดุจแปรง
// 21. **สกุณไกรสร:** ลำตัวเป็นสิงห์ หัวเป็นนก (สกุณ)
// 22. **สิงฆ์:** สิงโตทั่วไปตามรูปแบบจิตรกรรมไทย
// 23. **สิงหคาวี:** รูปร่างคล้ายไกรสรคาวี คือสิงห์ผสมวัว
// 24. **สิงหคักคา:** ลำตัวเป็นสิงห์ แต่มีเกล็ดปกคลุมคล้ายคางคกหรือตะกวด
// 25. **สิงหพานร:** ท่อนบนเป็นลิง ท่อนล่างเป็นสิงห์
// 26. **สิงโตจีน:** สุนัขสิงโต สัตว์มงคลตามคติความเชื่อของจีน
// 27. **สีหรามังกร:** ลำตัวเป็นสิงห์ หัวเป็นมังกร
// 28. **เทพนรสีห์:** ท่อนบนเป็นมนุษย์ ท่อนล่างเป็นสิงห์
// 29. **ฑิชากรจตุบท:** สัตว์ 4 เท้า ลำตัวเป็นสิงห์ หัวและปีกเป็นนก
// 30. **โต:** สัตว์สี่เท้าคล้ายสิงห์ มีเขาสองเขา หัวโต
// 31. **โตเทพสิงฆนัต:** รูปร่างคล้ายโต แต่มีเครื่องประดับแบบเทพ
// 32. **ทักทอ:** ลำตัวสิงห์ หัวช้าง คล้ายคชสีห์แต่มีผมและเคราดุดัน

// ### + สัตว์ประเภทม้า
// 33. **ดุรงค์ไกรสร:** ลำตัวเป็นม้า หัวเป็นสิงห์ มีกีบเท้าแบบม้า
// 34. **ดุรงค์ปักษิณ:** ลำตัวเป็นม้า มีปีกและหางเป็นนก กายสีขาว ขนคอสีดำ
// 35. **เหมราอัสดร:** ลำตัวเป็นม้า หัวเป็นเหม มีจงอยปากแหลม
// 36. **ม้า:** ม้าสายพันธุ์ดีในป่าหิมพานต์ วิ่งเร็วปานลม
// 37. **ม้าปีก:** ม้าที่มีปีกนก สามารถบินได้
// 38. **งายไส:** ลำตัวเป็นสิงห์หรือสุนัข หัวเป็นม้า มีเขี้ยว เป็นสัตว์กินเนื้อ
// 39. **สินธพกุญชร:** ลำตัวเป็นม้า หัวและงวงเป็นช้าง ผิวสีเขียวอ่อน
// 40. **สินธกนธี:** ลำตัวเป็นม้า หางเป็นปลา วิ่งบนผิวน้ำและดำน้ำได้
// 41. **โตเทพอัสดร:** ลำตัวเป็นม้า หัวเป็นโต (สิงห์มีเขา)
// 42. **อัสดรเหรา:** ลำตัวเป็นม้า หัวเป็นเหรา (จระเข้ผสมนาค)
// 43. **อัสดรวิหค:** ลำตัวเป็นม้า หัวและปีกเป็นนก

// ### + สัตว์ประเภทแรด
// 44. **ระมาด (เพิ่มเติม):** สัตว์คล้ายแรดผสมสมเสร็จ มีนอที่จมูก บางตำราวาดให้มีเกล็ด

// ### + สัตว์ประเภทช้าง
// 45. **เอราวัณ:** ช้างเผือก 33 เศียร พาหนะของพระอินทร์ จ้าวแห่งช้าง
// 46. **กรินทร์ปักษา:** ลำตัวเป็นช้าง มีปีกและหางเป็นนก บินบนฟ้าได้
// 47. **วารีกุญชร:** ครึ่งหน้าเป็นช้าง ครึ่งหลังเป็นปลา ไม่มีขาหลัง อาศัยในน้ำ
// 48. **ช้างเผือก:** ช้างมงคลผิวสีอ่อน สัญลักษณ์ของผู้มีบุญญาธิการ

// ### + สัตว์ประเภทวัวควาย
// 49. **มังกรวิหค:** วัวหรือควายป่าที่มีเกล็ดแบบมังกรและมีปีกนก
// 50. **ทรพี / ทรพา:** ควายป่าสีดำทมิฬ ทรพาคือพ่อ ทรพีคือลูกที่เนรคุณฆ่าพ่อตัวเอง

// ### + สัตว์ประเภทลิง
// 51. **กบิลปักษา:** ลิงเพศผู้สีดำ มีปีกที่ไหล่และมีหางเป็นนก
// 52. **มัจฉานุ:** ท่อนบนเป็นลิง ท่อนล่างเป็นปลา ลูกของหนุมานกับนางสุพรรณมัจฉา

// ### + สัตว์ประเภทสุนัข
// 53. **โกลน (เพิ่มเติม):** สุนัขป่าหิมพานต์ มักอยู่เป็นฝูง ปราดเปรียวและดุร้าย

// ### + สัตว์ประเภทนก
// 54. **อสูรปักษา:** ท่อนบนเป็นยักษ์ ท่อนล่างเป็นนก
// 55. **อสุรวายุพักตร์:** ยักษ์กินลม มีลำตัวท่อนล่างเป็นนกอินทรี ตรากระทรวงการคลัง
// 56. **ไก่:** ไก่แก้ว หรือไก่ฟ้าหิมพานต์ มีขนสีรุ้งแวววาว
// 57. **นกการเวก:** นกสวรรค์ที่มีเสียงร้องไพเราะที่สุดในสามโลก
// 58. **ครุฑ:** พญานกครึ่งคนครึ่งนกอินทรี พาหนะของพระนารายณ์ ศัตรูของนาค
// 59. **หงส์:** นกสวรรค์ชั้นสูง สัญลักษณ์ของความบริสุทธิ์และพาหนะของพระพรหม
// 60. **หงส์จีน:** เฟิ่งหวง นกมงคลของจีน สัญลักษณ์ของจักรพรรดินี
// 61. **คชปักษา:** ลำตัวเป็นนก แต่มีหัวและงวงเป็นช้าง
// 62. **มยุระคนธรรพ์:** ลำตัวเป็นนกยูง หัวและท่อนบนเป็นคนธรรพ์
// 63. **มยุระเวนไตย:** ลำตัวเป็นนกยูง หัวและปีกเป็นครุฑ
// 64. **มังกรสกุณี:** ลำตัวเป็นนก หัวเป็นมังกร
// 65. **นาคปักษี:** ท่อนบนเป็นนก ท่อนล่างเป็นนาค (เป็นผู้หญิง)
// 66. **นาคปักษิณ:** ครึ่งนกครึ่งนาค (เป็นผู้ชาย)
// 67. **นกหัสดี:** นกยักษ์ที่มีหัวและงวงเป็นช้าง ตัวใหญ่พอจะโฉบช้างกินได้
// 68. **นกอินทรี:** พญานกนักล่าขนาดใหญ่ในป่าหิมพานต์
// 69. **นกเทศ:** นกกระจอกเทศหิมพานต์ วิ่งเร็วและมีพละกำลังมาก
// 70. **พยัคฆ์เวนไตย:** ลำตัวเป็นเสือ หัวและปีกเป็นครุฑ
// 71. **นกสดายุ:** พญานกในรามเกียรติ์ ถูกทศกัณฐ์ฟันปีกขาดขณะช่วยนางสีดา
// 72. **เสือปีก:** เสือโคร่งหรือเสือดาวที่มีปีกนก
// 73. **สกุณเหรา:** ลำตัวเป็นนก หัวเป็นเหรา (จระเข้ผสมนาค)
// 74. **สินธุปักษี:** ครึ่งนกครึ่งปลา อาศัยอยู่ตามแหล่งน้ำ
// 75. **สีหสุบรรณ:** ลำตัวเป็นสิงห์ หัวและปีกเป็นครุฑ
// 76. **สุบรรณเหรา:** ลำตัวเป็นครุฑ หัวเป็นเหรา
// 77. **นกสัมพาที:** พี่ชายของสดายุ ถูกแสงอาทิตย์เผาจนขนร่วงหมดตัว
// 78. **เทพกินนร:** ท่อนบนเป็นชายรูปงาม ท่อนล่างเป็นนก เก่งดนตรี
// 79. **เทพกินรี:** ท่อนบนเป็นหญิงรูปงาม ท่อนล่างเป็นนก เก่งฟ้อนรำ
// 80. **เทพปักษี:** เทวดาที่มีปีกนกอยู่กลางหลัง
// 81. **นกทัณฑิมา:** นกรูปร่างคล้ายมนุษย์ ถือไม้เท้า ทำหน้าที่เป็นยามทวารบาล

// ### + สัตว์ประเภทปลา
// 82. **เหมวาริน:** หัวเป็นเหม ลำตัวและหางเป็นปลา
// 83. **กุญชรวารี:** คล้ายวารีกุญชร คือครึ่งช้างครึ่งปลา
// 84. **มัจฉนาคา:** หัวเป็นพญานาค ลำตัวเป็นปลา
// 85. **มัจฉวาฬ:** ปลาวาฬยักษ์แห่งทะเลหิมพานต์
// 86. **นางเงือก:** ครึ่งบนเป็นหญิงสาว ครึ่งล่างเป็นปลา
// 87. **ปลาควาย:** หัวเป็นควาย ลำตัวเป็นปลา
// 88. **ปลาเสือ:** หัวเป็นเสือ ลำตัวเป็นปลา
// 89. **ศฤงคมัสยา:** ปลาวิเศษที่มีเขาบนหัว

// ### + สัตว์ประเภทจระเข้
// 90. **กุมภีร์นิมิต:** จระเข้ยักษ์ที่มีอิทธิฤทธิ์จำแลงกายได้
// 91. **เหรา:** ครึ่งนาคครึ่งจระเข้ มีขา ดุร้าย มักอยู่ตามบันไดวัด

// ### + สัตว์ประเภทปู
// 92. **ปูหิมพานต์ (กงกาง - เพิ่มเติม):** ปูยักษ์กระดองหนา ก้ามใหญ่ทรงพลัง อาศัยในสระใหญ่

// ### + สัตว์ประเภทนาค
// 93. **พญานาค (เพิ่มเติม):** งูใหญ่มีหงอน จ้าวแห่งโลกบาดาลและผู้บันดาลน้ำ

// ### + สัตว์ประเภทมนุษย์
// 94. **คนธรรพ์:** ครึ่งมนุษย์ครึ่งเทวดา ชำนาญดนตรีและการปรุงยาสมุนไพร
// 95. **มักกะลีผล (นารีผล):** ผลไม้วิเศษรูปร่างเหมือนหญิงสาวเปลือยกาย มีชีวิตอยู่ได้ 7 วัน

